public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;
        // Priority queue: [i, j, remaining_k, cost]
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[3]));
        pq.offer(new long[]{0, 0, k, 0});

        // Visited: [i][j][remaining_k] -> min cost
        long[][][] visited = new long[m][n][(int)k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                Arrays.fill(visited[i][j], Long.MAX_VALUE);
            }
        }
        visited[0][0][(int)k] = 0;

        int[][] dirs = {{0, 1}, {1, 0}}; // right and down

        while (!pq.isEmpty()) {
            long[] curr = pq.poll();
            int i = (int)curr[0];
            int j = (int)curr[1];
            long remainingK = curr[2];
            long cost = curr[3];

            if (i == m - 1 && j == n - 1) {
                return cost;
            }

            if (cost > visited[i][j][(int)remainingK]) {
                continue;
            }

            // Normal moves
            for (int[] dir : dirs) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < visited[ni][nj][(int)remainingK]) {
                        visited[ni][nj][(int)remainingK] = newCost;
                        pq.offer(new long[]{ni, nj, remainingK, newCost});
                    }
                }
            }

            // Teleport moves
            if (remainingK > 0) {
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j] && (x != i || y != j)) {
                            long newCost = cost;
                            if (newCost < visited[x][y][(int)(remainingK - 1)]) {
                                visited[x][y][(int)(remainingK - 1)] = newCost;
                                pq.offer(new long[]{x, y, remainingK - 1, newCost});
                            }
                        }
                    }
                }
            }
        }
        return -1;
    }
}
