import java.util.*;

public static long solve(long[][] grid, long k) {
    int m = grid.length;
    int n = grid[0].length;
    long[][][] dist = new long[m][n][(int)k + 1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            Arrays.fill(dist[i][j], Long.MAX_VALUE);
        }
    }
    dist[0][0][0] = 0;

    PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
    pq.offer(new long[]{0, 0, 0, 0});

    int[][] dirs = {{0, 1}, {1, 0}};

    while (!pq.isEmpty()) {
        long[] curr = pq.poll();
        long cost = curr[0];
        int i = (int)curr[1];
        int j = (int)curr[2];
        int usedK = (int)curr[3];

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > dist[i][j][usedK]) {
            continue;
        }

        // Normal moves
        for (int[] dir : dirs) {
            int ni = i + dir[0];
            int nj = j + dir[1];
            if (ni < 0 || ni >= m || nj < 0 || nj >= n) {
                continue;
            }
            long newCost = cost + grid[ni][nj];
            if (newCost < dist[ni][nj][usedK]) {
                dist[ni][nj][usedK] = newCost;
                pq.offer(new long[]{newCost, ni, nj, usedK});
            }
        }

        // Teleport moves
        if (usedK < k) {
            for (int x = 0; x < m; x++) {
                for (int y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j] && (x != i || y != j)) {
                        if (cost < dist[x][y][usedK + 1]) {
                            dist[x][y][usedK + 1] = cost;
                            pq.offer(new long[]{cost, x, y, usedK + 1});
                        }
                    }
                }
            }
        }
    }

    long min = Long.MAX_VALUE;
    for (int i = 0; i <= k; i++) {
        min = Math.min(min, dist[m - 1][n - 1][i]);
    }
    return min;
}
