import java.util.*;

public static long solve(long[][] grid, long k) {
    int m = grid.length;
    int n = grid[0].length;
    long[][][] dist = new long[m][n][(int)k + 1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            Arrays.fill(dist[i][j], Long.MAX_VALUE);
        }
    }
    PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[2]));
    pq.offer(new long[]{0, 0, 0, 0});
    dist[0][0][0] = 0;

    int[][] dirs = {{0, 1}, {1, 0}};

    while (!pq.isEmpty()) {
        long[] curr = pq.poll();
        int x = (int)curr[0];
        int y = (int)curr[1];
        long usedK = curr[3];
        long cost = curr[2];

        if (x == m - 1 && y == n - 1) {
            return cost;
        }

        if (cost > dist[x][y][(int)usedK]) {
            continue;
        }

        // Try normal moves
        for (int[] dir : dirs) {
            int nx = x + dir[0];
            int ny = y + dir[1];
            if (nx >= 0 && nx < m && ny >= 0 && ny < n) {
                long newCost = cost + grid[nx][ny];
                if (newCost < dist[nx][ny][(int)usedK]) {
                    dist[nx][ny][(int)usedK] = newCost;
                    pq.offer(new long[]{nx, ny, newCost, usedK});
                }
            }
        }

        // Try teleport if possible
        if (usedK < k) {
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    if (i == x && j == y) continue;
                    if (grid[i][j] <= grid[x][y]) {
                        if (cost < dist[i][j][(int)usedK + 1]) {
                            dist[i][j][(int)usedK + 1] = cost;
                            pq.offer(new long[]{i, j, cost, usedK + 1});
                        }
                    }
                }
            }
        }
    }

    long min = Long.MAX_VALUE;
    for (int i = 0; i <= k; i++) {
        if (dist[m-1][n-1][i] < min) {
            min = dist[m-1][n-1][i];
        }
    }
    return min;
}
